import { randomBytes, createHash } from 'react-native-crypto';
import base64url from 'base64url';

/**
 * Generate a cryptographically random code verifier for PKCE.
 * RFC 7636 requires 43-128 characters from [A-Z, a-z, 0-9, "-", ".", "_", "~"].
 */
export function generateCodeVerifier() {
  const buffer = randomBytes(32);
  return base64url.encode(buffer);
}

/**
 * Generate the code challenge from the verifier using S256 method.
 */
export function generateCodeChallenge(codeVerifier) {
  if (!codeVerifier || typeof codeVerifier !== 'string') {
    throw new Error('Invalid code verifier');
  }
  const hash = createHash('sha256').update(codeVerifier).digest();
  return base64url.encode(hash);
}

/**
 * Generate a cryptographically random state parameter to prevent CSRF.
 */
export function generateState() {
  const buffer = randomBytes(16);
  return base64url.encode(buffer);
}


