import * as Keychain from 'react-native-keychain';
import EncryptedStorage from 'react-native-encrypted-storage';

const TOKEN_KEYS = {
  ACCESS_TOKEN: 'oauth_access_token',
  REFRESH_TOKEN: 'oauth_refresh_token',
  TOKEN_EXPIRY: 'oauth_token_expiry',
  ID_TOKEN: 'oauth_id_token',
};

Object.freeze(TOKEN_KEYS);

/**
 * Store tokens securely using platform keychain/keystore.
 * NEVER store tokens in AsyncStorage, SharedPreferences plaintext, or logs.
 */
export async function storeTokens({ accessToken, refreshToken, expiresIn, idToken }) {
  if (!accessToken || typeof accessToken !== 'string') {
    throw new Error('Invalid access token');
  }

  const expiryTimestamp = Date.now() + (expiresIn * 1000);

  try {
    await EncryptedStorage.setItem(
      TOKEN_KEYS.ACCESS_TOKEN,
      accessToken
    );

    if (refreshToken) {
      await EncryptedStorage.setItem(
        TOKEN_KEYS.REFRESH_TOKEN,
        refreshToken
      );
    }

    await EncryptedStorage.setItem(
      TOKEN_KEYS.TOKEN_EXPIRY,
      expiryTimestamp.toString()
    );

    if (idToken) {
      await EncryptedStorage.setItem(
        TOKEN_KEYS.ID_TOKEN,
        idToken
      );
    }
  } catch (error) {
    // Do NOT log token values
    console.error('Failed to store tokens securely');
    throw new Error('Secure storage operation failed');
  }
}

export async function getAccessToken() {
  try {
    return await EncryptedStorage.getItem(TOKEN_KEYS.ACCESS_TOKEN);
  } catch {
    return null;
  }
}

export async function getRefreshToken() {
  try {
    return await EncryptedStorage.getItem(TOKEN_KEYS.REFRESH_TOKEN);
  } catch {
    return null;
  }
}

export async function getTokenExpiry() {
  try {
    const expiry = await EncryptedStorage.getItem(TOKEN_KEYS.TOKEN_EXPIRY);
    return expiry ? parseInt(expiry, 10) : null;
  } catch {
    return null;
  }
}

export async function clearTokens() {
  try {
    await EncryptedStorage.removeItem(TOKEN_KEYS.ACCESS_TOKEN);
    await EncryptedStorage.removeItem(TOKEN_KEYS.REFRESH_TOKEN);
    await EncryptedStorage.removeItem(TOKEN_KEYS.TOKEN_EXPIRY);
    await EncryptedStorage.removeItem(TOKEN_KEYS.ID_TOKEN);
  } catch {
    console.error('Failed to clear tokens');
  }
}

export async function isTokenExpired() {
  const expiry = await getTokenExpiry();
  if (!expiry) return true;
  // Consider token expired 60 seconds before actual expiry for safety margin
  return Date.now() >= (expiry - 60000);
}


