/**
 * Validate authorization code format.
 * Authorization codes should be alphanumeric with limited special characters.
 */
export function validateAuthorizationCode(code) {
  if (!code || typeof code !== 'string') {
    return false;
  }
  // Authorization codes are typically alphanumeric, may include hyphens and underscores
  const codePattern = /^[a-zA-Z0-9\-_\.]{10,512}$/;
  return codePattern.test(code);
}

/**
 * Validate state parameter matches expected value.
 */
export function validateState(received, expected) {
  if (!received || !expected) return false;
  if (typeof received !== 'string' || typeof expected !== 'string') return false;
  // Constant-time comparison to prevent timing attacks
  if (received.length !== expected.length) return false;
  let result = 0;
  for (let i = 0; i < received.length; i++) {
    result |= received.charCodeAt(i) ^ expected.charCodeAt(i);
  }
  return result === 0;
}

/**
 * Validate URL to prevent open redirect attacks.
 */
export function validateRedirectUri(uri, expectedUri) {
  if (!uri || typeof uri !== 'string') return false;
  return uri === expectedUri;
}

/**
 * Sanitize error messages to prevent information leakage.
 */
export function sanitizeErrorMessage(error) {
  const safeErrors = {
    'invalid_grant': 'Authentication failed. Please try again.',
    'invalid_request': 'Invalid request. Please try again.',
    'unauthorized_client': 'Application not authorized.',
    'access_denied': 'Access denied by user.',
    'server_error': 'Server error. Please try again later.',
    'temporarily_unavailable': 'Service temporarily unavailable.',
  };
  return safeErrors[error] || 'An unexpected error occurred.';
}


