// --- services/apiClient.js ---
import authService from './authService';

/**
 * Secure API client with automatic token refresh.
 * Attaches valid access tokens and handles 401 responses.
 */
class ApiClient {
  constructor(baseUrl) {
    if (!baseUrl || !baseUrl.startsWith('https://')) {
      throw new Error('API base URL must use HTTPS');
    }
    this.baseUrl = baseUrl;
    this.maxRetries = 1;
  }

  async request(endpoint, options = {}, retryCount = 0) {
    const accessToken = await authService.getValidAccessToken();

    if (!accessToken) {
      throw new Error('Not authenticated');
    }

    // Validate endpoint to prevent path traversal
    if (endpoint.includes('..') || endpoint.includes('://')) {
      throw new Error('Invalid endpoint');
    }

    const url = `${this.baseUrl}${endpoint}`;

    const headers = {
      'Authorization': `Bearer ${accessToken}`,
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      ...options.headers,
    };

    try {
      const response = await fetch(url, {
        ...options,
        headers,
      });

      // Handle 401 - attempt token refresh and retry once
      if (response.status === 401 && retryCount < this.maxRetries) {
        try {
          await authService.refreshAccessToken();
          return this.request(endpoint, options, retryCount + 1);
        } catch {
          // Refresh failed, propagate the 401
          throw new Error('Authentication expired');
        }
      }

      return response;
    } catch (error) {
      // Do NOT log request details that might contain sensitive data
      console.error(`API request failed for ${endpoint}`);
      throw error;
    }
  }

  async get(endpoint, options = {}) {
    return this.request(endpoint, { ...options, method: 'GET' });
  }

  async post(endpoint, data, options = {}) {
    return this.request(endpoint, {
      ...options,
      method: 'POST',
      body: JSON.stringify(data),
    });
  }

  async put(endpoint, data, options = {}) {
    return this.request(endpoint, {
      ...options,
      method: 'PUT',
      body: JSON.stringify(data),
    });
  }

  async delete(endpoint, options = {}) {
    return this.request(endpoint, { ...options, method: 'DELETE' });
  }
}

export default ApiClient;


// --- context/AuthContext.js ---
import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { Linking, AppState } from 'react-native';
import authService from '../services/authService';
import OAuthConfig from '../config/oauth';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const appState = useRef(AppState.currentState);

  // Check authentication status on mount
  useEffect(() => {
    const checkAuth = async () => {
      try {
        const authenticated = await authService.isAuthenticated();
        if (authenticated) {
          // Verify token is still valid
          const token = await authService.getValidAccessToken();
          setIsAuthenticated(!!token);
        } else {
          setIsAuthenticated(false);
        }
      } catch {
        setIsAuthenticated(false);
      } finally {
        setIsLoading(false);
      }
    };

    checkAuth();
  }, []);

  // Handle deep link callbacks
  useEffect(() => {
    const handleDeepLink = async (event) => {
      const url = event.url || event;
      if (url && url.startsWith(OAuthConfig.redirectUri)) {
        try {
          setIsLoading(true);
          setError(null);
          await authService.handleCallback(url);
          setIsAuthenticated(true);
        } catch (err) {
          setError(err.message);
          setIsAuthenticated(false);
        } finally {
          setIsLoading(false);
        }
      }
    };

    const subscription = Linking.addEventListener('url', handleDeepLink);

    // Check if app was opened via deep link
    Linking.getInitialURL().then((url) => {
      if (url && url.startsWith(OAuthConfig.redirectUri)) {
        handleDeepLink(url);
      }
    });

    return () => {
      subscription.remove();
    };
  }, []);

  // Proactively refresh token when app comes to foreground
  useEffect(() => {
    const subscription = AppState.addEventListener('change', async (nextAppState) => {
      if (
        appState.current.match(/inactive|background/) &&
        nextAppState === 'active' &&
        isAuthenticated
      ) {
        try {
          const token = await authService.getValidAccessToken();
          if (!token) {
            setIsAuthenticated(false);
          }
        } catch {
          setIsAuthenticated(false);
        }
      }
      appState.current = nextAppState;
    });

    return () => {
      subscription.remove();
    };
  }, [isAuthenticated]);

  const login = useCallback(async () => {
    try {
      setIsLoading(true);
      setError(null);
      const result = await authService.authorize();
      if (result) {
        setIsAuthenticated(true);
      }
      // If result is null, we're waiting for deep link callback
    } catch (err) {
      setError(err.message);
      setIsAuthenticated(false);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const logout = useCallback(async () => {
    try {
      setIsLoading(true);
      await authService.logout();
    } catch {
      // Continue with local logout even if server revocation fails
    } finally {
      setIsAuthenticated(false);
      setIsLoading(false);
      setError(null);
    }
  }, []);

  const value = {
    isAuthenticated,
    isLoading,
    error,
    login,
    logout,
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}


